from outlines.prompts import prompt, register_filter, unregister_filter

register_filter('shout', lambda s: s.upper() + '!')

@prompt
def greet(name):
    '''Hello {{ name | shout }}'''

print(greet('world'))

unregister_filter('shout')

try:
    print(greet('world'))
except Exception as e:
    print('Expected error after unregister:', type(e).__name__)

# test precedence: local/builtin filter 'name' should not be overridden
register_filter('name', lambda x: 'HIJACKED')

@prompt
def show_name(fn):
    '''{{ fn | name }}'''

def foo(): pass

print(show_name(foo))
"
